INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('ab2b3d3e-570d-5d49-b6e6-2ff6a33436f7', 'math-2eme', 'المقارنة والترتيب', 'مقارنة الأعداد إلى 999 بالرموز < و > و =، والترتيب التصاعديّ والتنازليّ، والسابق والتالي والتدوير البسيط إلى أقرب عشرة', '# ⚔️ المقارنة والترتيب — من الأصغر إلى الأكبر

> 💡 «لمعرفة الأكبر، ابدأ دائمًا من أعلى رتبة على اليسار.»

عبرت بوّابة الأعداد، أيّها البطل، وصرت تقرأ وتكتب كلّ عددٍ إلى 999. اليوم نتعلّم سلاحًا جديدًا: كيف **نقارن** عددين ونعرف أيّهما أكبر، وكيف **نرتّب** مجموعةً من الأعداد.

## 🏰 رموز المقارنة

نستعمل ثلاثة رموزٍ لمقارنة عددين:

| الرمز | معناه   | مثال    |
| ----- | ------- | ------- |
| <     | أصغر من | 25 < 52 |
| >     | أكبر من | 80 > 30 |
| =     | يساوي   | 40 = 40 |

> 🗡️ حيلة لتذكّر الرمز: فُوّهة الرمز المفتوحة تتّجه دائمًا نحو **العدد الأكبر**، والطرف المدبّب نحو الأصغر.

## 🧮 كيف نقارن عددين؟

نتّبع قاعدتين بسيطتين:

1. العدد ذو **عدد الأرقام الأكبر** هو الأكبر: 5 < 40 لأنّ 40 من رقمين، و 99 < 100.
2. إذا تساوى عدد الأرقام، نقارن **رقمًا رقمًا من اليسار** (من أعلى رتبة)، والحُكم لأوّل اختلاف.

_مثال:_ نقارن 327 و 319: المئات متساوية (3 = 3)، ثمّ العشرات: 2 > 1، إذن 327 > 319.

> ⚠️ الفخّ الشائع: الظنّ أنّ 198 أكبر من 200 لأنّ فيه الرقم 9؛ والصواب أنّ 200 من ثلاثة أرقام أكبر… بل كلاهما من ثلاثة أرقام، نقارن المئات: 1 < 2، إذن 198 < 200.

## 🔮 الترتيب التصاعديّ والتنازليّ

بعد المقارنة نستطيع **ترتيب** عدّة أعدادٍ:

- **تصاعديًّا**: من الأصغر إلى الأكبر، مثل 45 < 120 < 308.
- **تنازليًّا**: من الأكبر إلى الأصغر، مثل 308 > 120 > 45.

## ⚡ السابق والتالي

لكلّ عددٍ **تالٍ** (يليه) هو العدد زائد 1، و**سابق** (يسبقه) هو العدد ناقص 1:

- تالي 99 هو 100، وسابقه هو 98.
- تالي 560 هو 561، وسابقه هو 559.

## 🛡️ التدوير إلى أقرب عشرة

أحيانًا نريد قيمةً **مقرّبة** أقرب إلى عشرةٍ كاملة. ننظر إلى رقم **الآحاد**:

- إذا كان **5 أو أكثر** نُدوّر إلى الأعلى، وإذا كان **أقلّ من 5** نُبقي العشرة كما هي.
- _مثال:_ 47 أقرب عشرة هي 50 (لأنّ الآحاد 7 ≥ 5)، و 43 أقرب عشرة هي 40 (لأنّ الآحاد 3 < 5).

> 🏆 ممتاز! صرت تقارن وترتّب وتعرف السابق والتالي وتُدوّر إلى أقرب عشرة. استعدّ الآن للبوّابة الموالية: عمليّة **الجمع**.', '# 📜 ملخّص: المقارنة والترتيب

- **رموز المقارنة:** < أصغر من، > أكبر من، = يساوي؛ والفُوّهة المفتوحة تتّجه نحو الأكبر.
- **قاعدة المقارنة:** الأكثر أرقامًا أكبر؛ وعند تساوي عدد الأرقام نقارن رقمًا رقمًا من اليسار، والحُكم لأوّل اختلاف.
- **الترتيب التصاعديّ:** من الأصغر إلى الأكبر، مثل 45 < 120 < 308.
- **الترتيب التنازليّ:** من الأكبر إلى الأصغر، مثل 308 > 120 > 45.
- **التالي:** العدد زائد 1 (تالي 99 هو 100)؛ **السابق:** العدد ناقص 1 (سابق 100 هو 99).
- **التدوير إلى أقرب عشرة:** ننظر إلى الآحاد، إن كان ≥ 5 نُدوّر إلى الأعلى وإلّا نُبقي العشرة.', 3, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('17f22ebc-1e14-53e3-aebb-193c3d2d58c0', 'math-2eme', 'الجمع', 'معنى الجمع ومفرداته (الحدّان، المجموع)، الجمع في حدود 999 بدون احتفاظ ومع الاحتفاظ (la retenue)، خاصيّة الإبدال (ترتيب الحدّين لا يغيّر المجموع)، جمع الصفر، وحلّ مسائل بسيطة', '# ⚔️ الجمع — مهارة البطل في ضمّ الكنوز

> 💡 «من يُتقن الجمع يَجمع كنوزه دون أن يضيع منه شيء.»

أهلًا بك أيّها البطل! اليوم نتعلّم سحرًا قويًّا اسمه **الجمع**: نضمّ به عددين أو أكثر فنحصل على عددٍ واحدٍ أكبر. سنجمع أعدادًا إلى **999**، تارةً بسهولة وتارةً مع حيلةٍ ذكيّة اسمها **الاحتفاظ**.

## 🏰 ما معنى الجمع؟

الجمع هو أن **نضمّ** كميّتين معًا لنعرف المجموع كلّه. علامته **+** وتُقرأ «زائد».

- إذا كان معك 3 تفّاحات وأعطاك صديقك 4 تفّاحات، صار عندك 3 + 4 = 7 تفّاحات.
- الجمع يجعل العدد **يكبر** (إلّا إذا جمعنا 0).

## 🧮 مفردات الجمع: الحدّان والمجموع

في العمليّة 25 + 13 = 38:

- العددان 25 و 13 هما **الحدّان** (كلّ واحدٍ منهما **حدّ**).
- العدد 38 هو **المجموع** (نتيجة الجمع).

نقرأها: «25 زائد 13 يساوي 38».

## 🔮 الجمع دون احتفاظ

نُرتّب العددين **رتبةً تحت رتبة**: الآحاد تحت الآحاد، والعشرات تحت العشرات، والمئات تحت المئات. ثمّ نجمع كلّ رتبةٍ على حدة، من **اليمين إلى اليسار**.

_مثال:_ 234 + 142

- الآحاد: 4 + 2 = 6
- العشرات: 3 + 4 = 7
- المئات: 2 + 1 = 3
- المجموع: 234 + 142 = 376

> 🗡️ احرص دائمًا أن تكون الأرقام **تحت بعضها بالضبط**: آحادٌ مع آحاد، فلا تخلط الرتب.

## ⚡ الجمع مع الاحتفاظ (la retenue)

أحيانًا يكون مجموع رتبةٍ **أكبر من 9** (أي 10 أو أكثر). عندئذٍ نكتب رقم الآحاد، و**نحتفظ** بالعشرة فنضيفها إلى الرتبة الموالية.

_مثال:_ 27 + 15

- الآحاد: 7 + 5 = 12. نكتب 2 ونحتفظ بـ 1 (عشرة واحدة).
- العشرات: 2 + 1 = 3، نضيف المحتفَظ به: 3 + 1 = 4.
- المجموع: 27 + 15 = 42.

القاعدة: **كلّما بلغ مجموع رتبةٍ عشرةً أو أكثر، نَحتفظ بعشرةٍ واحدةٍ للرتبة التالية.**

> ⚠️ الفخّ الشائع: نسيان **المحتفَظ به**! في 27 + 15 لو نسيت العشرة لكتبت 32 بدل 42. لا تنسَ أن تضيف المحتفَظ به.

## 🛡️ خاصيّة الإبدال وجمع الصفر

**ترتيب الحدّين لا يغيّر المجموع** (خاصيّة الإبدال):

$$8 + 5 = 5 + 8 = 13$$

فإن صعُب عليك 2 + 137، اقلبها إلى 137 + 2 = 139، النتيجة هي نفسها.

أمّا **الصفر** فهو الحدّ الهادئ: جمعُ 0 لا يغيّر شيئًا.

- 7 + 0 = 7
- 0 + 350 = 350

> 🏆 أحسنت أيّها البطل! صرت تعرف معنى الجمع ومفرداته، وتجمع دون احتفاظ ومع احتفاظ، وتعرف أنّ ترتيب الحدّين لا يهمّ، وأنّ الصفر لا يغيّر المجموع. اجمع كنوزك الآن إلى 999 بثقة!', '# 📜 ملخّص: الجمع

- **معنى الجمع:** ضمّ كميّتين أو أكثر لمعرفة المجموع كلّه، وعلامته **+** («زائد»).
- **المفردات:** في 25 + 13 = 38، العددان 25 و 13 هما **الحدّان**، و 38 هو **المجموع**.
- **الجمع دون احتفاظ:** نرتّب رتبةً تحت رتبة (آحاد تحت آحاد) ونجمع كلّ رتبةٍ من اليمين إلى اليسار، مثل 234 + 142 = 376.
- **الجمع مع الاحتفاظ:** إذا بلغ مجموع رتبةٍ 10 أو أكثر، نكتب رقم الآحاد و**نحتفظ** بعشرةٍ للرتبة التالية، مثل 27 + 15 = 42.
- **لا تنسَ المحتفَظ به:** أضف العشرة المحتفظ بها إلى الرتبة الموالية، وإلّا كانت النتيجة خاطئة.
- **خاصيّة الإبدال:** ترتيب الحدّين لا يغيّر المجموع: 8 + 5 = 5 + 8 = 13.
- **جمع الصفر:** جمعُ 0 لا يغيّر العدد: 7 + 0 = 7 و 0 + 350 = 350.
- **المسائل:** في مسائل الجمع نضمّ الكميّات معًا لنجد المجموع الكلّي.', 4, NULL)
