INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('23987ed4-8c3c-5c46-93a0-2e2df44f94ec', 'math-2eme', 'الطرح', 'معنى الطرح ومفرداته (المطروح منه، المطروح، الفرق)، الطرح في حدود 999 بدون استلاف ومع الاستلاف، طرح الصفر والعدد من نفسه، والتثبّت من الطرح بالجمع', '# ⚔️ الطرح — سيف إنقاص الأعداد

> 💡 «الجمعُ يَبني والطرحُ يَهدم؛ ومن أتقنهما معًا صار سيّدَ الأعداد.»

أهلًا بك أيّها البطل! في الفصل السابق تعلّمت **الجمع**. اليوم نمسك سيفًا جديدًا اسمه **الطرح**: به نَعرف **كم بقي** بعد أن نُنقص عددًا من عدد، ونحسب **الفرق** بين عددين، إلى حدود 999.

## 🏰 ما معنى الطرح؟

الطرح يعني **الإنقاص**: نأخذ عددًا ونُنقص منه عددًا آخر، فنعرف **كم بقي**.

- مثال: عندي 9 تفّاحات، أكلتُ 4، كم بقي؟ نطرح: 9 − 4 = 5. بقيت 5 تفّاحات.
- نستعمل الطرح أيضًا لنعرف **الفرق** بين عددين: الفرق بين 8 و 3 هو 8 − 3 = 5.

نكتب علامة الطرح هكذا **−**، ونقرؤها «ناقص».

## 🧮 أسماء أطراف الطرح

في كلّ عمليّة طرح ثلاثة أسماء يجب أن تحفظها:

| الاسم              | مكانه                       | مثال في 7 − 2 = 5 |
| ------------------ | --------------------------- | ----------------- |
| **المطروح منه**    | العدد الأوّل (الأكبر عادةً) | 7                 |
| **المطروح**        | العدد الذي نُنقصه           | 2                 |
| **الفرق** (الباقي) | نتيجة الطرح                 | 5                 |

> 🗡️ تذكّر الترتيب: **المطروح منه − المطروح = الفرق**. العدد الأكبر يُكتب أوّلًا.

## 🔮 الطرح بدون استلاف

نضع العددين أحدهما تحت الآخر، كلّ رتبةٍ تحت رتبتها (آحاد تحت آحاد، عشرات تحت عشرات، مئات تحت مئات)، ثمّ نطرح **رتبةً رتبةً ابتداءً من اليمين** (من الآحاد).

- مثال: 568 − 243. الآحاد: 8 − 3 = 5. العشرات: 6 − 4 = 2. المئات: 5 − 2 = 3. إذن 568 − 243 = 325.

ما دام كلّ رقمٍ في الأعلى **أكبر من أو يساوي** الرقم الذي تحته، نطرح مباشرةً دون أيّ صعوبة.

## ⚡ الطرح مع الاستلاف

أحيانًا يكون الرقم في الأعلى **أصغر** من الرقم الذي تحته، فلا نستطيع الطرح مباشرةً. هنا نستعمل **الاستلاف**: نأخذ **عشرةً واحدة** من الرتبة المجاورة على اليسار.

- مثال: 52 − 27. الآحاد: 2 أصغر من 7! نستلف عشرةً من العشرات: تصير الآحاد 12، والعشرات تنقص واحدة (من 5 إلى 4). الآن: 12 − 7 = 5 في الآحاد، و 4 − 2 = 2 في العشرات. إذن 52 − 27 = 25.

> ⚠️ الفخّ الخطير: لا تطرح أبدًا **الأصغر من الأكبر داخل الرتبة** للهروب من الاستلاف! في 52 − 27 الآحاد ليست 7 − 2 = 5، بل نستلف: 12 − 7 = 5. النتيجة الصحيحة 25، لا 35.

## 🛡️ الطرح عكس الجمع والتثبّت

**الطرح عكس الجمع.** إذا كان 5 + 3 = 8، فإنّ 8 − 3 = 5 و 8 − 5 = 3.

لذلك نتثبّت من صحّة الطرح **بالجمع**: نجمع **الفرق** مع **المطروح**، فإن حصلنا على **المطروح منه** فالجواب صحيح.

- مثال: حسبنا 52 − 27 = 25. نتثبّت: 25 + 27 = 52 ✓. الجواب صحيح.

## 📐 حالات خاصّة سهلة

- **طرح الصفر:** إذا طرحنا 0 لا يتغيّر العدد: 47 − 0 = 47.
- **طرح العدد من نفسه:** الفرق يساوي 0 دائمًا: 36 − 36 = 0 (أخذنا كلّ شيء فلم يبقَ شيء).
- **مسائل بالكلمات:** اقرأ المسألة جيّدًا. كلمات مثل «كم بقي؟»، «كم أكل؟»، «الفرق» تدلّ على الطرح. مثال: في صندوقٍ 120 كرة، بِيعت 45، كم بقي؟ نطرح: 120 − 45 = 75 كرة.

> 🏆 رائع أيّها البطل! صرت تعرف معنى الطرح وأسماء أطرافه، وتطرح بدون استلاف ومع الاستلاف، وتتثبّت بالجمع. سيفُ الطرح في يدك الآن — انطلق إلى التمارين!', '# 📜 ملخّص: الطرح

- **معنى الطرح:** الإنقاص ومعرفة كم بقي أو الفرق بين عددين، مثل 9 − 4 = 5؛ علامته **−** وتُقرأ «ناقص».
- **أطراف الطرح:** **المطروح منه** (العدد الأوّل) − **المطروح** = **الفرق** (الباقي)، مثل في 7 − 2 = 5.
- **الطرح بدون استلاف:** نطرح رتبةً رتبةً ابتداءً من الآحاد على اليمين، مثل 568 − 243 = 325.
- **الطرح مع الاستلاف:** إذا كان الرقم الأعلى أصغر، نستلف عشرةً من الرتبة المجاورة على اليسار، مثل 52 − 27 = 25.
- **الطرح عكس الجمع:** إذا كان 5 + 3 = 8 فإنّ 8 − 3 = 5.
- **التثبّت بالجمع:** نجمع الفرق مع المطروح فنجد المطروح منه، مثل 25 + 27 = 52 ✓.
- **طرح الصفر:** لا يتغيّر العدد: 47 − 0 = 47.
- **طرح العدد من نفسه:** الفرق 0 دائمًا، مثل 36 − 36 = 0.
- **المسائل بالكلمات:** كلمات «كم بقي؟» و«الفرق» تدلّ على الطرح، مثل 120 − 45 = 75.', 5, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('9c1fe2f0-bf3b-594f-81fa-d1b38a3a8e41', 'math-2eme', 'مدخل الضرب', 'الضرب كجمعٍ متكرّر، علامة × ومصطلحاته (العاملان والجداء)، قراءة a × b، جداول الضرب 2 و3 و4 و5، الضرب في 1 وفي 0، وخاصيّة الإبدال a × b = b × a', '# ⚔️ مدخل الضرب — سلاح الجمع السريع

> 💡 «لماذا نجمع العدد نفسه مرّاتٍ كثيرة؟ تعلّم الضرب فتُنجز العمل في خطوةٍ واحدة.»

أهلًا بك أيّها البطل! تعرف من قبلُ كيف تَجمع. اليوم نتعلّم **الضرب**، وهو سلاحٌ سريعٌ يختصر جمع العدد نفسِه مرّاتٍ كثيرة.

## 🏰 الضرب جمعٌ متكرّر

تخيّل 4 صناديق، في كلّ صندوقٍ 3 جواهر. كم جوهرةً معك؟

نجمع: 3 + 3 + 3 + 3 = 12. وهذا الجمع المتكرّر نكتبه ضربًا:

$$4 × 3 = 12$$

إذن **الضرب** هو جمعُ العدد نفسِه عدّةَ مرّات. نقول 4 × 3 ونقرؤها «**4 مرّاتٍ 3**»، أي 3 مجموعًا 4 مرّات.

## 🧮 العاملان والجداء

في كلّ عمليّة ضرب:

- العددان اللذان نضربهما يُسمّيان **العامِلَين**.
- نتيجة الضرب تُسمّى **الجداء**.

_مثال:_ في 4 × 3 = 12، العاملان هما 4 و 3، والجداء هو 12.

> 🗡️ علامة الضرب هي ×. اكتبها دائمًا بين العامِلَين: 4 × 3، ولا تنسَها.

## 🔮 جداول الضرب 2 و 3

نتعلّم الجداول لنحسب بسرعة دون جمعٍ طويل. هذا جدول الضرب في 2 وفي 3:

| العدد | × 2 | × 3 |
| ----- | --- | --- |
| 1     | 2   | 3   |
| 2     | 4   | 6   |
| 3     | 6   | 9   |
| 4     | 8   | 12  |
| 5     | 10  | 15  |
| 6     | 12  | 18  |
| 7     | 14  | 21  |
| 8     | 16  | 24  |
| 9     | 18  | 27  |

الضرب في 2 يعني **المضاعفة**: 2 × 6 = 6 + 6 = 12.

## ⚡ جداول الضرب 4 و 5

وهذا جدول الضرب في 4 وفي 5:

| العدد | × 4 | × 5 |
| ----- | --- | --- |
| 1     | 4   | 5   |
| 2     | 8   | 10  |
| 3     | 12  | 15  |
| 4     | 16  | 20  |
| 5     | 20  | 25  |
| 6     | 24  | 30  |
| 7     | 28  | 35  |
| 8     | 32  | 40  |
| 9     | 36  | 45  |

في جدول 5 تنتهي كلّ النتائج بالرقم 0 أو 5: 5، 10، 15، 20… وهذا يساعدك على تذكّرها.

## 🛡️ الضرب في 1 وفي 0

قاعدتان سهلتان وثابتتان:

- **الضرب في 1:** كلّ عددٍ مضروبٍ في 1 يبقى كما هو: a × 1 = a. مثال: 7 × 1 = 7.
- **الضرب في 0:** كلّ عددٍ مضروبٍ في 0 يساوي 0: a × 0 = 0. مثال: 8 × 0 = 0.

> ⚠️ احذر الفخّ: 5 × 0 ليست 5 بل **0** (لا شيء، صفر مرّات). و 5 × 1 = 5 وليست 0.

## 📐 خاصيّة الإبدال

ترتيب العامِلَين لا يُغيّر الجداء:

$$a × b = b × a$$

مثال: 3 × 4 = 12 و 4 × 3 = 12، فهما متساويان. فإذا حفظت 3 × 4 فقد عرفت 4 × 3 أيضًا!

> 🏆 أحسنت أيّها البطل! صرت تعرف معنى الضرب وعامِلَيه وجداءه، وتحفظ جداول 2 و 3 و 4 و 5، وتُتقن الضرب في 1 وفي 0 وخاصيّة الإبدال. استعدّ الآن لخوض التمارين!', '# 📜 ملخّص: مدخل الضرب

- **الضرب جمعٌ متكرّر:** 3 + 3 + 3 + 3 = 4 × 3 = 12.
- **القراءة:** a × b تُقرأ «a مرّاتٍ b»، مثل 4 × 3 «أربع مرّاتٍ ثلاثة».
- **المصطلحات:** العددان المضروبان هما **العامِلان**، ونتيجة الضرب هي **الجداء**.
- **علامة الضرب** هي × ونكتبها بين العامِلَين.
- **جدول 2:** 2، 4، 6، 8، 10، 12، 14، 16، 18 (المضاعفة).
- **جدول 3:** 3، 6، 9، 12، 15، 18، 21، 24، 27.
- **جدول 4 وجدول 5:** نتائج جدول 5 تنتهي دائمًا بـ 0 أو 5.
- **الضرب في 1:** a × 1 = a؛ و**الضرب في 0:** a × 0 = 0.
- **خاصيّة الإبدال:** a × b = b × a، مثل 3 × 5 = 5 × 3 = 15.', 6, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('51188630-1600-59af-ada2-22ca72044649', 'math-2eme', 'القيس: الأطوال والزمن', 'قيس الأطوال بالمتر (m) والصنتيمتر (cm) والعلاقة 1 m = 100 cm، وقراءة الساعة والنصف ساعة، واليوم (24 ساعة) والأسبوع (7 أيّام) وأيّام الأسبوع', '# ⚔️ القيس: الأطوال والزمن — مغامرة المسطرة والساعة

> 💡 «من يَعرف يَقيس، يَعرف كم يبعُد الكنز وكم بقي من الوقت.»

أهلًا بك أيّها البطل! في هذه المغامرة نتعلّم أمرين مهمّين: كيف **نقيس الأطوال** بالمسطرة، وكيف **نقرأ الوقت** على الساعة. هما سلاحان يساعدانك كلّ يوم.

## 🏰 ما هو القيس؟

**القيس** هو أن نعرف كم يبلغ شيءٌ ما: طوله، أو الوقت الذي يمضي. نحتاج دائمًا إلى **وحدة** نقيس بها.

- نقيس **الأطوال** بالمتر (m) والصنتيمتر (cm).
- نقيس **الزمن** بالساعة واليوم والأسبوع.

## 📏 الأطوال: المتر والصنتيمتر

نقيس الطول بأداة اسمها **المسطرة**. على المسطرة نرى تدريجاتٍ صغيرة، كلّ تدريجة هي **صنتيمتر واحد (1 cm)**.

- **الصنتيمتر (cm)** وحدة صغيرة: نقيس بها طول قلمٍ أو دفتر.
- **المتر (m)** وحدة كبيرة: نقيس بها طول الباب أو الطاولة.

العلاقة الأساسيّة التي يجب أن تحفظها:

$$1 m = 100 cm$$

لقياس طولٍ بالمسطرة، نضع البداية عند العلامة **0**، ثمّ نقرأ الرقم عند نهاية الشيء. إذا انتهى القلم عند العلامة 12، فطوله **12 cm**.

> 🗡️ لتحويل الأمتار إلى صنتيمترات، نضرب في **100**: فمثلًا 3 m = 3 × 100 = 300 cm. وللعكس، نقسم على 100: 400 cm = 4 m.

## 🔮 مقارنة الأطوال وجمعها

لكي نقارن طولين، يجب أن يكونا **بنفس الوحدة**.

- إذا كان الأوّل 8 cm والثاني 5 cm، فالأوّل أطول لأنّ 8 أكبر من 5.
- إذا أردنا جمع طولين بنفس الوحدة، نجمع الأعداد: 20 cm + 30 cm = 50 cm.

أحيانًا نكتب الطول بوحدتين معًا: 250 cm = 200 cm + 50 cm = **2 m و 50 cm**.

> ⚠️ احذر الفخّ! للتحويل من الأمتار إلى الصنتيمترات نضرب في **100** وليس في 10. فالعدد 2 m يساوي 200 cm وليس 20 cm.

## ⏰ الزمن: قراءة الساعة

على وجه الساعة عقربان: **العقرب الصغير** يدلّ على الساعات، و**العقرب الكبير** يدلّ على الدقائق.

- عندما يشير العقرب الكبير إلى **12**، نقرأ ساعةً كاملة: إن كان الصغير على 3 فالوقت **الساعة 3**.
- عندما يشير العقرب الكبير إلى **6**، نقرأ **النصف**: إن كان الصغير بين 3 و 4 فالوقت **الساعة 3 والنصف**.

النصف ساعة يساوي **30 دقيقة**، والساعة الكاملة تساوي **60 دقيقة**.

## 🛡️ اليوم والأسبوع والشهر

- **اليوم** فيه **24 ساعة**: نهارٌ نلعب فيه ونتعلّم، وليلٌ ننام فيه.
- **الأسبوع** فيه **7 أيّام**، وهي بالترتيب: السبت، الأحد، الاثنين، الثلاثاء، الأربعاء، الخميس، الجمعة.
- **الشهر** فيه تقريبًا **4 أسابيع** (حوالى 30 يومًا).

نرتّب الأيّام كما نعدّ: بعد الاثنين يأتي الثلاثاء، وقبل الخميس يأتي الأربعاء.

> 🗡️ لتجد اليوم الموالي، فكّر في الترتيب: ما بعد الجمعة هو السبت (نبدأ الأسبوع من جديد).

> 🏆 رائع أيّها البطل! صرت تقيس الأطوال بالمتر والصنتيمتر، وتعرف أنّ 1 m = 100 cm، وتقرأ الساعة والنصف ساعة، وتعرف أيّام الأسبوع. خذ مسطرتك وساعتك واستعدّ للتحدّي!', '# 📜 ملخّص: القيس: الأطوال والزمن

- نقيس **الأطوال** بالمسطرة، ووحدتاها **المتر (m)** و**الصنتيمتر (cm)**.
- العلاقة الأساسيّة: **1 m = 100 cm**.
- للتحويل من الأمتار إلى الصنتيمترات نضرب في **100**: 2 m = 200 cm، و 4 m = 400 cm.
- للعكس نقسم على 100: 300 cm = 3 m، و 250 cm = 2 m و 50 cm.
- لمقارنة أو جمع طولين يجب أن يكونا **بنفس الوحدة**: 20 cm + 30 cm = 50 cm.
- على الساعة: العقرب الكبير على **12** يعني ساعةً كاملة، وعلى **6** يعني **النصف ساعة**.
- **اليوم** فيه **24 ساعة**، و**الأسبوع** فيه **7 أيّام**.
- أيّام الأسبوع بالترتيب: السبت، الأحد، الاثنين، الثلاثاء، الأربعاء، الخميس، الجمعة.
- نرتّب الأيّام كما نعدّ: بعد الاثنين الثلاثاء، وبعد الجمعة يعود السبت.', 7, NULL)
ON CONFLICT (id) DO UPDATE SET
