  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('ba3779f9-c1ab-5ebe-b1a7-3b1b026e748b', 'math-2eme', 'النقود', 'القطع النقدية بالمليم (5 إلى 200 مي) والدينار (1 د = 1000 مي) ونصف الدينار، تمثيل مبلغ وبأقلّ عدد من القطع، جمع المبالغ ومقارنتها', '# ⚔️ النقود — من المليم إلى الدينار

> 💡 «من يُتقن النقود يَشتري ويَبيع بثقة.»

أيّها البطل، تعلّمتَ القطع الصغيرة بالمليم. اليوم نُوسّع: قطعٌ أكبر، ونتعرّف على **الدينار**.

## 🪙 الوحدات والقطع

نَعُدّ بالـ**مليم** (مي) وبالـ**دينار** (د)، والعلاقة بينهما: **1 د = 1000 مي**.

- قطع المليم: 5، 10، 20، 50، 100، 200 مي.
- **نصف الدينار = 500 مي**.

## 💰 نُمثّل مبلغًا

نختار قطعًا مجموعُ قيمها يساوي المبلغ:

- _مثال:_ 70 مي = 50 مي + 20 مي.
- _مثال:_ 250 مي = 200 مي + 50 مي.

## 🔁 بأقلِّ عددٍ من القطع

نبدأ بالقطع الكبيرة لِنستعمل أقلَّ عددٍ ممكن:

- _مثال:_ 250 مي بأقلّ القطع = 200 مي + 50 مي (قطعتان).

## ➕ نجمع المبالغ

نجمع قيمَ القطع لإيجاد المبلغ الكلّيّ:

- _مثال:_ 200 مي + 200 مي + 100 مي = 500 مي، أي نصف دينار.

## ⚖️ نقارن المبالغ

نقارن **قيمتَي** المبلغين، لا عددَ القطع:

- _مثال:_ نصف دينار (500 مي) أكبرُ من 300 مي.

> ⚠️ الفخّ الشائع: قطعةٌ واحدة من 200 مي أكبرُ قيمةً من ثلاث قطعٍ من 50 مي (مجموعها 150 مي).

> 🏆 أحسنت أيّها البطل! صرتَ تتعامل بالمليم والدينار، وتُمثّل المبالغ وتجمعها وتقارنها!', '# 📜 ملخّص: النقود

- **الوحدات**: المليم (مي) والدينار (د)، و **1 د = 1000 مي** ؛ نصف الدينار = 500 مي.
- **القطع**: 5، 10، 20، 50، 100، 200 مي.
- **تمثيل مبلغ**: نختار قطعًا مجموعُ قيمها = المبلغ (250 مي = 200 + 50).
- **بأقلّ القطع**: نبدأ بالقطع الكبيرة.
- **الجمع**: نجمع قيمَ القطع لإيجاد المبلغ الكلّيّ.
- **المقارنة**: نقارن قيمةَ المبلغين، لا عددَ القطع.', 8, NULL)
